import{createDesmosGraphs,desmosColors}from"/scripts/src/desmos.min.js";import{raw}from"/scripts/src/main.min.js";function getDerivativeString(n){var r=["f"];for(let e=0;e<n;e++)r.push("'");return r.push("(a)"),r.join("")}export default function(){var r=[];for(let e=0;e<=10;e++)r.push(getDerivativeString(e));createDesmosGraphs({taylorSeries:{bounds:{xmin:-10,xmax:10,ymin:-10,ymax:10},expressions:[{latex:raw`f(x) = \sin(x)`,color:desmosColors.purple},{latex:raw`\sum_{n = 0}^N \frac{D[n + 1]}{n!} (x-a)^n`,color:desmosColors.blue},{latex:raw`N = 5`,sliderBounds:{min:0,max:10,step:1}},{latex:raw`a = 0`},{latex:raw`(a, f(a))`,color:desmosColors.blue,pointSize:50,secret:!0},{latex:raw`D = [${r.join(", ")}]`,secret:!0}]},taylorSeriesComparison:{bounds:{xmin:-5,xmax:15,ymin:-10,ymax:10},expressions:[{latex:raw`f(x) = \sin(x)`,color:desmosColors.purple},{latex:raw`N = 5`,sliderBounds:{min:0,max:10,step:1}},{latex:raw`F_1(x) = \sum_{n = 0}^N \frac{D(0)[n + 1]}{n!} (x)^n`,color:desmosColors.blue},{latex:raw`F_2(x) = \sum_{n = 0}^N \frac{D(3\pi)[n + 1]}{n!} (x-3\pi)^n`,color:desmosColors.red},{latex:raw`f(10)`},{latex:raw`F_2(10)`},{latex:raw`F_1(10)`},{latex:raw`D(a) = [${r.join(", ")}]`,hidden:!0,secret:!0}]},problematicTaylorSeries:{bounds:{xmin:-2.5,xmax:2.5,ymin:-2.5,ymax:2.5},expressions:[{latex:raw`f(x) = \{x = 0: 0, e^{-\frac{1}{x^2}}\}`,color:desmosColors.purple},{latex:raw`\sum_{n = 0}^N \frac{D[n + 1]}{n!} (x-a)^n`,color:desmosColors.blue},{latex:raw`N = 5`,sliderBounds:{min:0,max:10,step:1}},{latex:raw`a = 0`},{latex:raw`(a, f(a))`,color:desmosColors.blue,secret:!0},{latex:raw`D = [${r.slice(0,6).join(", ")}]`,secret:!0}]}})}